  ('medical-tech-moex-20661', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '下列何種感染病原最易引起肉芽腫 (granuloma) 性發炎反應？ 革蘭氏陽性球菌  革蘭氏陰性桿菌  痲瘋菌  疹病毒', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:15+00:00", "source_pdf_sha1": "410a76c9c225", "answer_pdf_sha1": "9fe68df2e674", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 80, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20662', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '吳先生的平均動脈壓為100 mmHg，心輸出量（cardiac output）為每分鐘5公升，心跳為每分鐘70次，經 服藥後其動脈壓為70 mmHg，心輸出量為每分鐘4.5公升，心跳為每分鐘90次。則該藥有何作用？ 降低心搏量（stroke volume）  增加心搏工作量（stroke work） 增加週邊血管總阻力（total peripheral resistance）  增加心室舒張末期體積（end-diastolic volume）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "c666316c921a", "answer_pdf_sha1": "c8ad2e506300", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20663', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '李老先生因腿疾就醫，經檢查發現其左股動脈（femoral artery）血流為每分鐘500 mL，右股動脈血流為每 分鐘300 mL，股靜脈壓力為10 mmHg，而股動脈之平均動脈壓為100 mmHg。則下列何者正確？ 其右股動脈阻力為3.3 mL/min/mmHg  其右股動脈阻力為0.3 mmHg/mL/min 其左右股動脈合起來的阻力為0.48 mmHg/mL/min  其右股動脈血管阻力小於左股動脈阻力', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "c666316c921a", "answer_pdf_sha1": "c8ad2e506300", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20664', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '循環系統中那一個區域的血量（blood volume）最多？ 心臟  動脈  靜脈  微血管', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "c666316c921a", "answer_pdf_sha1": "c8ad2e506300", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20665', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '下列有關血腦屏障（blood-brain barrier）的敘述何者最正確？ 為一種限制腦組織攝取養分的疾病 因腦微血管壁被緊密結合（tight junction）密封所致 因腦微血管壁被間隙結合（gap junction）密封所致 氧氣需藉由運輸蛋白（transporter）通過血腦屏障', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "c666316c921a", "answer_pdf_sha1": "c8ad2e506300", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20666', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '若胸壁回縮的彈力（elastic recoil）為甲，肺組織回縮的彈力為乙，則正常人在呼氣期終止時，甲、乙兩者 彈力的方向為何？ 甲向外，乙向內  甲向內，乙向外  甲與乙皆向內  甲與乙皆向外', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "c666316c921a", "answer_pdf_sha1": "c8ad2e506300", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
